function generateWaveform(waveType) {
    const points = [];
    const width = 200;
    const height = 60;
    const centerY = height / 2;
    let frequency = 1;
    let amplitude = 15;
    switch(waveType){
        case "Alpha Wave":
            frequency = 2;
            amplitude = 20;
            break;
        case "Beta Wave":
            frequency = 4;
            amplitude = 15;
            break;
        case "Gamma Wave":
            frequency = 6;
            amplitude = 10;
            break;
        case "Theta Wave":
            frequency = 1.5;
            amplitude = 18;
            break;
    }
    for(let x = 0; x <= width; x += 2){
        const y = centerY + Math.sin(x / width * Math.PI * 2 * frequency) * amplitude;
        points.push(`${x},${y}`);
    }
    return `M ${points.join(" L ")}`;
}
